// // This module implements a 10-bit ring counter that generates a sequence of states where a single '0' circulates through the counter's bits.
module ring_counter_10bit(
    input clk,
    input reset,
    output reg [9:0] q
);

always @(posedge clk or posedge reset)
    if (reset)
        q <= 10'b0000000001; // Reset state
    else
        q <= {q[8:0], q[9]}; // Ring counter sequence

endmodule
